send-request.set-body:
@{
          var rawToken = context.Request.Headers.GetValueOrDefault("Authorization", "").Replace("Bearer ", "");
          var ba = (string)context.Variables["backend-audience"];
          var ci = (string)context.Variables["nv-obo-client-id"];
          var cs = (string)context.Variables["nv-obo-client-secret"];
          return "grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer&client_id=" + Uri.EscapeDataString(ci) + "&client_secret=" + Uri.EscapeDataString(cs) + "&assertion=" + Uri.EscapeDataString(rawToken) + "&scope=" + Uri.EscapeDataString(ba + "/.default") + "&requested_token_use=on_behalf_of";
        }

return-response.set-body:
@{
              return new JObject(new JProperty("error","obo_exchange_failed"),new JProperty("error_description","Token exchange to downstream service failed. Check APIM logs for details.")).ToString();
            }
